import {
  BotonTema,
  Footer,
  Header2,
  Github,
} from "../reutilizables/componentes";

import { useState } from "react";

function borrarToken() {
  localStorage.removeItem("token");
  window.history.back();
}

function cambiarContraseña() {
  const [idUsuarios, setUsuario] = useState("");
  const [cNueva, setCNueva] = useState("");
  const [confirmC, setConfirmC] = useState("");
  const [codigo, setCVerificacion] = useState("");

  const handleSolicitarCodigo = async () => {
    const res = await fetch("http://localhost:4000/api/cambiarContraseña", {
      method: "POST",
      headers: {
        "Content.Type": "application/json",
        body: JSON.stringify({
          idUsuarios: idUsuarios,
          cNueva: cNueva,
          confirmC: confirmC,
        }),
      },
    });
  };
  return (
    <div>
      <BotonTema />
      <div id="container">
        <header id="header1">
          <button id="volver" onClick={borrarToken}>
            Volver
          </button>
        </header>
        <Header2 />
        <section id="content">
          <input
            type="text"
            id="usuarios"
            placeholder="usuario"
            value={idUsuarios}
            onChange={(e) => setUsuario(e.target.value)}
          ></input>
          <input
            type="text"
            id="cNueva"
            placeholder="contraseña nueva"
            value={cNueva}
            onChange={(e) => setCNueva(e.target.value)}
          ></input>
          <input
            type="text"
            id="confirmC"
            placeholder="confirmar contraseña"
            value={confirmC}
            onChange={(e) => setConfirmC(e.target.value)}
          ></input>
          <input
            type="text"
            id="cVerificacion"
            placeholder="codigo de verificación"
            value={codigo}
            onChange={(e) => setCVerificacion(e.target.value)}
          ></input>

          <button id="enviar" className="principales">
            Solicitar codigo
          </button>
          <a href="/inicioSesion">
            <button id="aceptar" className="principales">
              Cambiar contraseña
            </button>
          </a>
          <a href="/" onClick={borrarToken}>
            <button id="cancelar" className="secundarios">
              cancelar
            </button>
          </a>
        </section>
        <Footer />
      </div>
      <Github />
    </div>
  );
}

export default cambiarContraseña;
